from agent import *from models.products import *import timedef strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.browser.use_new_parser = True    session.queue(Request('https://www.displayninja.com/reviews/monitors/page/1/', use='curl', force_charset='utf-8'), process_revlist, dict())def process_revlist(data, context, session):    strip_namespace(data)    revs = data.xpath('//main[@id="main"]/article')    for rev in revs:        name = rev.xpath('.//h2[@class="entry-title"]/a/text()').string()        url = rev.xpath('.//h2[@class="entry-title"]/a/@href').string()        if name and url:            session.queue(Request(url, use='curl', force_charset='utf-8', max_age=0), process_review, dict(name=name, url=url))    next_url = data.xpath('//div[@class="nav-links"]/a[contains(@class, "next")]/@href').string()    if next_url:        session.queue(Request(next_url, use='curl', force_charset='utf-8'), process_revlist, dict())def process_review(data, context, session):    strip_namespace(data)    ssid = data.xpath('//article/@id').string()    if not ssid and not context.get('reload'):        time.sleep(18)        session.do(Request(data.response_url, use='curl', force_charset='utf-8', max_age=0), process_review, dict(context, reload=True))        return    product = Product()    product.name = context["name"].split(" Review: ")[0]    product.url = data.xpath('//a[@class="review-button"]/@href').string() or context['url']    product.ssid = ssid.split('-')[-1]    product.category = 'Monitors'    review = Review()    review.title = context["name"]    review.url = context["url"]    review.type = "pro"    review.ssid = product.ssid    date = data.xpath('//time[contains(@class, "published")]/@datetime').string()    if date:        review.date = date.split("T")[0]    author = data.xpath('//span[contains(@class, "author-name")]/text()').string()    if author:        review.authors.append(Person(name=author, ssid=author))    pros = data.xpath('//div[@class="fs-pros"]//ul/li[not(contains(., "Pros:"))]/text()[normalize-space()]').strings()    for pro in pros:        pro = pro.strip('*+=-_\n ')        review.add_property(type="pros", value=pro)    cons = data.xpath('//div[@class="fs-cons"]//ul/li[not(contains(., "Cons:"))]/text()[normalize-space()]').strings()    for con in cons:        con = con.strip('*+=-_\n ')        if con:            review.add_property(type="cons", value=con)    grades = data.xpath('//div[@class="review-criteria"]/div')    for grade in grades:        grade_name = grade.xpath('//div[@class="review-criteria-title"]/text()').string()        grade_value = grade.xpath('//span[contains(@class, "number")]/text()').string()        if grade_name and grade_value:            grade_name = grade_name.strip(': ')            grade_value = float(grade_value.replace(',', '.').strip('()'))            review.grades.append(Grade(name=grade_name, value=grade_value, best=5.0))    grade_overall = data.xpath('//div[@class="review-rating"]/div[@class="rating-number"]/text()').string()    if grade_overall:        grade_overall = grade_overall.replace(',', '.').strip('( )')        if grade_overall:            review.grades.append(Grade(type='overall', value=float(grade_overall), best=5.0))    summary = data.xpath('//div[@class="review-info"]/p//text()[normalize-space()]').string(multiple=True)    if summary and summary.strip():        review.add_property(type="summary", value=summary.strip())    conclusion = data.xpath('//div[@class="entry-content"]/h2[regexp:test(., "conclusion", "i")]/following-sibling::p//text()[normalize-space()]').string(multiple=True)    if conclusion and conclusion.strip():        review.add_property(type="conclusion", value=conclusion.strip())    excerpt = data.xpath('//div[@class="entry-content"]/p[not(preceding-sibling::h2[regexp:test(., "conclusion", "i")])]//text()').string(multiple=True)    if excerpt and excerpt.strip():        review.add_property(type="excerpt", value=excerpt)        product.reviews.append(review)        session.emit(product)